    BigDecimal x = parameterValues[0].getNumberValue();
    MathContext mathContext = expression.getConfiguration().getMathContext();
    if (x.compareTo(BigDecimal.ZERO) == 0) {
        return expression.convertValue(BigDecimal.ZERO);
